#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long a[500010],sum[500010];
const long long nulltag=-100000;
struct segment_tree
{
	struct node
	{
		long long l,r;
		long long lson,rson;
		long long sum,max1,grow_tag,cut_tag;
	}a[1500010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
		a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
		a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
	}
	void pushgrow(long long x,long long val)
	{
		if(x==0)
		{
			return;
		}
		a[x].sum+=(sum[a[x].r]-sum[a[x].l-1])*val;;
		a[x].max1+=val*(::a[a[x].r]);
		a[x].grow_tag+=val;
	}
	void pushcut(long long x,long long val)
	{
		if(val==nulltag||x==0)
		{
			return;
		}
		a[x].sum=val*(a[x].r-a[x].l+1);
		a[x].max1=val;
		a[x].cut_tag=val;
		a[x].grow_tag=0;
	}
	void pushdown(long long x)
	{
		long long ls=a[x].lson,rs=a[x].rson;
		if(a[x].cut_tag!=nulltag)
		{
			pushcut(ls,a[x].cut_tag);
			pushcut(rs,a[x].cut_tag);
			a[x].cut_tag=nulltag;
		}
		if(a[x].grow_tag)
		{
			pushgrow(ls,a[x].grow_tag);
			pushgrow(rs,a[x].grow_tag);
			a[x].grow_tag=0;
		}
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt;
		a[x].l=l;
		a[x].r=r;
		a[x].grow_tag=0;
		a[x].cut_tag=nulltag;
		if(l==r)
		{
			a[x].sum=0;
			return x;
		}
		long long mid=(l+r)>>1;
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	long long query(long long x,long long p)
	{
		if(a[x].l==a[x].r)
		{
			return (a[x].max1<p?n+1:a[x].l);
		}
		pushdown(x);
		if(a[a[x].lson].max1<p)
		{
			return query(a[x].rson,p);
		}
		else
		{
			return query(a[x].lson,p);
		}
	}
	void cut(long long x,long long l,long long r,long long val)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			pushcut(x,val);
			return;
		}
		pushdown(x);
		cut(a[x].lson,l,r,val);
		cut(a[x].rson,l,r,val);
		pushup(x);
	}
	void grow(long long x,long long l,long long r,long long val)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			pushgrow(x,val);
			return;
		}
		pushdown(x);
		grow(a[x].lson,l,r,val);
		grow(a[x].rson,l,r,val);
		pushup(x);
	}
	long long getsum(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			return a[x].sum;
		}
		pushdown(x);
		return getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r);
	}
}t;
int main()
{
	scanf("%lld%lld",&n,&m);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&a[i]);
	}
	sort(a+1,a+1+n);
	for(long long i=1;i<=n;i++)
	{
		sum[i]=sum[i-1]+a[i];
	}
	t.init(1,n);
	long long pre=0;
	for(long long i=1;i<=m;i++)
	{
		long long d,b;
		scanf("%lld%lld",&d,&b);
		t.grow(1,1,n,d-pre);
		pre=d;
		long long p=t.query(1,b);
		long long ans=t.getsum(1,p,n)-(n-p+1)*b;
		printf("%lld\n",ans);
		t.cut(1,p,n,b);
	}
	return 0;
}
